let scope = 'full';
let keywords = [];
let stats = {};
let outliers = [];
let trending = [];
let rssTopics = [];
let categories = [];
try {
  const wh = $('Webhook 수신').all();
  if (wh.length) {
    const raw = wh[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.scope) scope = String(parsed.scope);
    if (Array.isArray(parsed?.keywords)) keywords = parsed.keywords.map(String);
    if (parsed?.stats && typeof parsed.stats === 'object') stats = parsed.stats;
    if (Array.isArray(parsed?.outliers)) outliers = parsed.outliers;
    if (Array.isArray(parsed?.trending)) trending = parsed.trending.map(String);
    if (Array.isArray(parsed?.rssTopics)) rssTopics = parsed.rssTopics.map(String);
    if (Array.isArray(parsed?.categories)) categories = parsed.categories.map(String);
  }
} catch {}
if (scope !== 'keyword') scope = 'full';
return [{ json: { scope, keywords, stats, outliers, trending, rssTopics, categories, source: 'n8n' } }];

const p = $input.first().json;
const outlierLines = (p.outliers || []).slice(0, 10).map((o, i) => {
  const title = o.title || o.name || '제목 없음';
  const vs = o.vsAvg != null ? ` vs.Avg ${Number(o.vsAvg).toFixed(1)}x` : '';
  return `${i + 1}. "${title}"${vs}`;
}).join('
') || '데이터 없음';

const trendLine = (p.trending || []).slice(0, 10).join(', ') || '데이터 없음';
const rssLine = (p.rssTopics || []).slice(0, 12).map((t, i) => `${i + 1}. ${t}`).join('
') || '데이터 없음';
const catLine = (p.categories || []).join(', ') || '미분류';
const stats = p.stats || {};
const kwLabel = (p.keywords || []).join(', ') || '';

const JSON_FORMAT = '[{"icon":"이모지","text":"설명 2-3문장","action":"추천 액션"}]';

let prompt = '';
if (p.scope === 'keyword' && kwLabel) {
  prompt = `당신은 유튜브 콘텐츠 전략가입니다.
키워드: ${kwLabel}

[관련 Outlier]
${outlierLines}

[RSS 주제]
${rssLine}

키워드 범위 안에서만 콘텐츠 제작 추천 4가지.
반드시 아래 JSON만 응답:
{"sections":[{"type":"personal","title":"🔍 «${kwLabel}» 키워드 인사이트","subtitle":"n8n · Gemini 분석","items":${JSON_FORMAT},"isAi":true}]}`;
} else {
  prompt = `당신은 멀티플랫폼 콘텐츠 전략가입니다. 아래 수집 데이터를 바탕으로 인사이트를 작성하세요.

[통계] 영상 ${stats.totalVideos ?? 0}개 · 평균 vs.Avg ${stats.avgVsAvg ?? 0} · Outlier ${stats.outlierCount ?? 0}개 · 채널 ${stats.channelCount ?? 0}개

[Outlier TOP]
${outlierLines}

[트렌딩 키워드]
${trendLine}

[RSS 주제]
${rssLine}

[채널 카테고리]
${catLine}

반드시 아래 JSON만 응답 (다른 텍스트 없이):
{"sections":[{"type":"korea","title":"🇰🇷 지금 한국 트렌드","subtitle":"Gemini 분석","items":${JSON_FORMAT},"isAi":true},{"type":"personal","title":"📊 내 데이터 기반 추천","subtitle":"수집 데이터 분석","items":${JSON_FORMAT},"isAi":true},{"type":"global","title":"🌐 글로벌 트렌드","subtitle":"Gemini 분석","items":${JSON_FORMAT},"isAi":true}]}`;
}


return [{ json: { ...p, geminiPrompt: prompt, geminiKey: $env.GEMINI_API_KEY || '' } }];

const params = $('Gemini 프롬프트 준비').first().json;
const geminiRaw = $input.first().json;

function parseSections(text) {
  if (!text) return null;
  try {
    const fence = text.match(/```(?:json)?\s*\n?([\s\S]*?)\n?```/);
    const cleaned = fence ? fence[1].trim() : text;
    const objMatch = cleaned.match(/\{[\s\S]*\}/);
    if (!objMatch) return null;
    const fixed = objMatch[0].replace(/,\s*([}\]])/g, '$1');
    const parsed = JSON.parse(fixed);
    if (Array.isArray(parsed.sections) && parsed.sections.length) return parsed.sections;
    if (Array.isArray(parsed) && parsed.length) return [{ type: 'personal', title: 'AI 인사이트', subtitle: 'n8n · Gemini', items: parsed, isAi: true }];
  } catch {}
  return null;
}

let sections = null;
try {
  const parts = geminiRaw?.candidates?.[0]?.content?.parts || [];
  const text = parts.filter(p => !p.thought).map(p => p.text || '').join('\n');
  sections = parseSections(text);
} catch {}

if (!sections) {
  const topOut = (params.outliers || [])[0];
  const fallbackItem = {
    icon: '📊',
    text: topOut ? `최고 Outlier «${topOut.title}» — vs.Avg ${Number(topOut.vsAvg || 0).toFixed(1)}x. 이 주제 각도로 파생 콘텐츠를 기획해 보세요.` : '수집 데이터를 바탕으로 Outlier·트렌딩 키워드를 조합한 콘텐츠를 기획해 보세요.',
    action: '콘텐츠 가이드에서 발행 주제 입력',
  };
  sections = params.scope === 'keyword' && (params.keywords || []).length
    ? [{ type: 'personal', title: `🔍 «${params.keywords.join(', ')}» 키워드 인사이트`, subtitle: 'Gemini 파싱 폴백', items: [fallbackItem], isAi: false }]
    : [
        { type: 'korea', title: '🇰🇷 지금 한국 트렌드', subtitle: 'Gemini 파싱 폴백', items: [{ icon: '💡', text: '한국 시니어·재테크 관련 숏폼·블로그 수요가 꾸준합니다.', action: '트렌딩 키워드 확인' }], isAi: false },
        { type: 'personal', title: '📊 내 데이터 기반 추천', subtitle: '수집 데이터 요약', items: [fallbackItem], isAi: false },
        { type: 'global', title: '🌐 글로벌 트렌드', subtitle: 'Gemini 파싱 폴백', items: [{ icon: '🌐', text: '글로벌 경제·라이프스타일 해설형 롱폼이 안정적 수요를 보입니다.', action: 'Outlier 분석' }], isAi: false },
      ];
}

return [{ json: { ok: true, mode: 'n8n', sections, generatedAt: new Date().toISOString(), aiEnhanced: !!geminiRaw?.candidates?.[0] } }];

const p = $input.first().json;
const topOut = (p.outliers || [])[0];
const item = {
  icon: '⚠️',
  text: topOut ? `GEMINI_API_KEY 미설정 — «${topOut.title}» 등 수집 데이터만 표시됩니다. n8n Docker에 GEMINI_API_KEY를 설정하세요.` : 'GEMINI_API_KEY 미설정 — n8n Docker .env에 키를 추가하세요.',
  action: '설정 → n8n Webhook 확인',
};
const sections = p.scope === 'keyword' && (p.keywords || []).length
  ? [{ type: 'personal', title: `🔍 «${p.keywords.join(', ')}» 키워드 인사이트`, subtitle: '규칙 기반 폴백', items: [item], isAi: false }]
  : [
      { type: 'personal', title: '📊 내 데이터 기반 추천', subtitle: '규칙 기반 폴백', items: [item], isAi: false },
    ];
return [{ json: { ok: true, mode: 'fallback', sections, generatedAt: new Date().toISOString(), message: 'GEMINI_API_KEY 미설정' } }];
